import{_ as a,c as i,ag as e,o as r}from"./chunks/framework.mHuDn-wg.js";const f=JSON.parse('{"title":"兼容模式","description":"","frontmatter":{},"headers":[],"relativePath":"计算机/Windows/word.md","filePath":"计算机/Windows/word.md","lastUpdated":null}'),o={name:"计算机/Windows/word.md"};function t(d,l,n,h,c,s){return r(),i("div",null,l[0]||(l[0]=[e('<h1 id="兼容模式" tabindex="-1">兼容模式 <a class="header-anchor" href="#兼容模式" aria-label="Permalink to &quot;兼容模式&quot;">​</a></h1><ul><li>Word 兼容模式是一种特殊的文档视图，用于确保高版本的Microsoft Word能够打开并正确显示由旧版本创建的文档。</li><li>主要目的是保持文档的原有格式和布局，同时限制一些新功能的使用，以确保文档在不同平台和软件之间顺利打开和保存。</li><li>兼容模式会带来一些限制：例如不能插入公式，图片控制点</li><li>转换兼容模式的方法：通过 <code>文件-信息</code>进行转换。</li><li>在 Word 2007 或 Word 2010 中创建的Word 在 2016 中打开时，文档窗口的标题栏中会显示 <strong>“兼容模式</strong> ”。 如果在 Word 2016 中打开 Word 2013 文档，则不会看到 <strong>兼容模式</strong> ，因为 Word 2013 和 Word 2016 已经兼容。</li><li><a href="https://support.microsoft.com/zh-cn/office/%E5%B0%86%E6%96%87%E6%A1%A3%E8%BD%AC%E6%8D%A2%E4%B8%BA%E8%BE%83%E6%96%B0%E7%9A%84%E6%A0%BC%E5%BC%8F-34ec742e-f0f9-4d95-bbe3-3ee8e30a86fa?NS=WINWORD&amp;Version=16&amp;SysLcid=2052&amp;UiLcid=2052&amp;AppVer=ZWD160&amp;HelpId=185764" target="_blank" rel="noreferrer">将文档转换为较新的格式 - Microsoft 支持</a></li></ul><h1 id="图片" tabindex="-1">图片 <a class="header-anchor" href="#图片" aria-label="Permalink to &quot;图片&quot;">​</a></h1><h2 id="图片控制点" tabindex="-1">图片控制点 <a class="header-anchor" href="#图片控制点" aria-label="Permalink to &quot;图片控制点&quot;">​</a></h2><ul><li>兼容模式影响图片控制点：兼容模式下图片会显示为实心控制点</li><li>环绕方式：当使用“紧密型环绕”或“穿越型环绕”时，图片周围会出现黑色实心正方形作为控制点，用于调整图片的位置和大小。而在其他环绕方式（如“浮于文字上方”、“衬于文字下方”等）中，图片周围则会出现空心的控制点。“嵌入型”图片通常会显示为实心方框，而其他格式（如“可浮动型”）则可能只显示空心的控制点</li></ul><h2 id="只显示方框不显示图片内容" tabindex="-1">只显示方框不显示图片内容 <a class="header-anchor" href="#只显示方框不显示图片内容" aria-label="Permalink to &quot;只显示方框不显示图片内容&quot;">​</a></h2><ul><li>选项-高级-显示文档内容-显示图片框</li><li>段落设置：如果图片只显示边框而无实际图像，可能是由于段落设置中的行距被设置为“固定行距”，导致图片无法完全显示。在这种情况下，可以尝试将行距改为“单倍行距”以解决这个问题。</li></ul><h2 id="无法同时选中两个图片" tabindex="-1">无法同时选中两个图片 <a class="header-anchor" href="#无法同时选中两个图片" aria-label="Permalink to &quot;无法同时选中两个图片&quot;">​</a></h2><ul><li>通常是因为图片的环绕方式设置为“嵌入型”。‌当图片的环绕方式为“嵌入型”时，图片会被视为文本的一部分，因此无法通过常规的方法同时选中多个图片。</li><li>可以将图片的环绕方式从“嵌入型”更改为其他类型，如“四周型”或“紧密型”。这样，就可以使用Ctrl键同时选中多个图片了。‌</li></ul><h1 id="文档部件" tabindex="-1">文档部件 <a class="header-anchor" href="#文档部件" aria-label="Permalink to &quot;文档部件&quot;">​</a></h1><ul><li>文档部件用于保存和重复使用特定的文档内容: 包括文本、图片、表格、域等</li></ul><h2 id="域" tabindex="-1">域 <a class="header-anchor" href="#域" aria-label="Permalink to &quot;域&quot;">​</a></h2><ul><li>域是一种特殊的代码，用于自动插入和更新文档中的信息。域类似于数据库中的字段或Excel中的函数，每个域都有一个唯一的名称，并由特定的代码构成，这些代码指导Word如何在文档中插入或显示信息</li><li>由花括号“{}”、域名（域代码）及选项开关构成</li><li>快捷键Ctrl+F9插入域，通过F9更新域，或者通过右键点击域选择“编辑域”来修改域的设置，ALT+F9显示或隐藏所有域代码</li><li>可以通过打印预览（Ctrl+P）的方式自动更新域，而不需要全选文档。</li><li>将域转化为普通文本的方法是使用快捷键“Ctrl + Shift + F9”，谨慎操作，建议备份</li></ul><h2 id="构建块" tabindex="-1">构建块 <a class="header-anchor" href="#构建块" aria-label="Permalink to &quot;构建块&quot;">​</a></h2><ul><li>构建块（Building Blocks）, 用于存储和重用文档中的固定格式内容</li><li>在“插入”选项卡 &gt;“文档部件” &gt;“构建基块管理器” 可以查看、编辑、添加或删除已有的构建块。</li><li>alt+F3 新建构建基块</li></ul><h1 id="样式表" tabindex="-1">样式表 <a class="header-anchor" href="#样式表" aria-label="Permalink to &quot;样式表&quot;">​</a></h1><ul><li>样式是格式指令的集合, 用于实现快速, 一致的文档排版</li><li>样式表可以与多级列表结合使用，以实现自动编号和目录功能</li></ul><h1 id="特殊字符" tabindex="-1">特殊字符 <a class="header-anchor" href="#特殊字符" aria-label="Permalink to &quot;特殊字符&quot;">​</a></h1><ul><li>带勾的方框: 使用 Wingding2 字体</li></ul><h1 id="alt键" tabindex="-1">Alt键 <a class="header-anchor" href="#alt键" aria-label="Permalink to &quot;Alt键&quot;">​</a></h1><p>Alt键的一些用法和技巧</p><ul><li>按下Alt键后，屏幕上方会显示一系列字母标识，这些标识对应于Word中的各种快捷功能</li><li>按住Alt键并拖动标尺或边框, 可以精确调整段落的缩进位置或表格的对齐方式</li><li>Alt+X 组合键可以转再字符及其Unicode代码之间转换 <ul><li>可以用啦插入特殊字符和代码</li><li>例如, 微米（μ）的Unicode代码是 <code>00B5</code>, 输入<code>00B5</code>再选中按下Alt+x则可变为字符<code>μ</code></li></ul></li></ul>',22)]))}const m=a(o,[["render",t]]);export{f as __pageData,m as default};
